mapper.sql:
SELECT T1.ID, T1.WORK_PLAN_ID, T1.DISPATCH_TYPE, T1.WORK_POSITION_CODE, T1.WORK_POSITION_NAME, T1.EQUIPMENT_TYPE_ID, T1.EQUIPMENT_TYPE_NAME, T1.EQUIPMENT_ID, T1.EQUIPMENT_NO, T1.OPERATORS_ID, T1.OPERATORS_NAME, T1.DEPT_ID, T1.DEPT_NAME, T1.REMARK, T1.CREATE_BY, T1.CREATE_BY_NAME, T1.CREATE_TIME, T1.UPDATE_BY, T1.UPDATE_BY_NAME, T1.UPDATE_TIME, T1.COMPANY_ID, T1.COMPANY_NAME, T1.NUMBER_COUNT, T1.SUB_PROCESS_CODE, T1.SUB_PROCESS_NAME FROM T_PRD_DISPATCH_SECONDARY T1 LEFT JOIN SYS_DEPT T2 ON T1.DEPT_ID = T2.ID
and T1.WORK_PLAN_ID = #{workPlanId}
and T1.DISPATCH_TYPE = #{dispatchType}
AND T2.DEPT_NO like #{deptNo_like,jdbcType=VARCHAR}
ORDER BY T1.EQUIPMENT_TYPE_NAME,T1.EQUIPMENT_NO

mapper.select:
SELECT T1.ID, T1.WORK_PLAN_ID, T1.DISPATCH_TYPE, T1.WORK_POSITION_CODE, T1.WORK_POSITION_NAME, T1.EQUIPMENT_TYPE_ID, T1.EQUIPMENT_TYPE_NAME, T1.EQUIPMENT_ID, T1.EQUIPMENT_NO, T1.OPERATORS_ID, T1.OPERATORS_NAME, T1.DEPT_ID, T1.DEPT_NAME, T1.REMARK, T1.CREATE_BY, T1.CREATE_BY_NAME, T1.CREATE_TIME, T1.UPDATE_BY, T1.UPDATE_BY_NAME, T1.UPDATE_TIME, T1.COMPANY_ID, T1.COMPANY_NAME, T1.NUMBER_COUNT, T1.SUB_PROCESS_CODE, T1.SUB_PROCESS_NAME FROM T_PRD_DISPATCH_SECONDARY T1 LEFT JOIN SYS_DEPT T2 ON T1.DEPT_ID = T2.ID
and T1.WORK_PLAN_ID = #{workPlanId}
and T1.DISPATCH_TYPE = #{dispatchType}
AND (T2.DEPT_NO like #{deptNo_like,jdbcType=VARCHAR}
${canDispatchDept}
)
ORDER BY T1.EQUIPMENT_TYPE_NAME,T1.EQUIPMENT_NO

SELECT T1.ID, T1.WORK_PLAN_ID, T1.DISPATCH_TYPE, T1.WORK_POSITION_CODE, T1.WORK_POSITION_NAME, T1.EQUIPMENT_TYPE_ID, T1.EQUIPMENT_TYPE_NAME, T1.EQUIPMENT_ID, T1.EQUIPMENT_NO, T1.OPERATORS_ID, T1.OPERATORS_NAME, T1.DEPT_ID, T1.DEPT_NAME, T1.REMARK, T1.CREATE_BY, T1.CREATE_BY_NAME, T1.CREATE_TIME, T1.UPDATE_BY, T1.UPDATE_BY_NAME, T1.UPDATE_TIME, T1.COMPANY_ID, T1.COMPANY_NAME, T1.NUMBER_COUNT, T1.SUB_PROCESS_CODE, T1.SUB_PROCESS_NAME, T1.DEPT_PARENT_ID, T1.DEPT_PARENT_NAME FROM T_PRD_DISPATCH_SECONDARY T1 LEFT JOIN SYS_DEPT T2 ON T1.DEPT_ID = T2.ID
and T1.WORK_PLAN_ID = #{workPlanId}
and T1.DISPATCH_TYPE = #{dispatchType}
AND T2.DEPT_NO like #{deptNo_like,jdbcType=VARCHAR}
ORDER BY T1.EQUIPMENT_TYPE_NAME,T1.EQUIPMENT_NO

SELECT t2.id AS deptId, t2.DEPT_NAME AS deptName FROM SYS_DEPT t2 LEFT JOIN SYS_DEPT t1 ON t2.PARENT_ID = t1.id AND t1.DEPT_LEVEL = 2 AND t1.IS_LABOR = 1 WHERE t2.DEPT_LEVEL = 4 AND t1.STATUS = '1' AND t2.STATUS = '1'
AND t2.DEPT_NO like #{deptNo_like}
ORDER BY t2.DEPT_NAME DESC

mapper.insert:
INSERT INTO T_PRD_DISPATCH_SECONDARY( ID, WORK_PLAN_ID, DISPATCH_TYPE, WORK_POSITION_CODE, WORK_POSITION_NAME, EQUIPMENT_TYPE_ID, EQUIPMENT_TYPE_NAME, EQUIPMENT_ID, EQUIPMENT_NO, OPERATORS_ID, OPERATORS_NAME, DEPT_ID, DEPT_NAME, COMPANY_ID, COMPANY_NAME, REMARK, NUMBER_COUNT, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME, SUB_PROCESS_CODE, SUB_PROCESS_NAME, DEPT_PARENT_ID, DEPT_PARENT_NAME ) (
SELECT #{item.id, jdbcType=VARCHAR}, #{item.workPlanId, jdbcType=VARCHAR}, #{item.dispatchType, jdbcType=VARCHAR}, #{item.workPositionCode, jdbcType=VARCHAR}, #{item.workPositionName, jdbcType=VARCHAR}, #{item.equipmentTypeId, jdbcType=VARCHAR}, #{item.equipmentTypeName, jdbcType=VARCHAR}, #{item.equipmentId, jdbcType=VARCHAR}, #{item.equipmentNo, jdbcType=VARCHAR}, #{item.operatorsId, jdbcType=BIGINT}, #{item.operatorsName, jdbcType=VARCHAR}, #{item.deptId, jdbcType=BIGINT}, #{item.deptName, jdbcType=VARCHAR}, #{item.companyId, jdbcType=BIGINT}, #{item.companyName, jdbcType=VARCHAR}, #{item.remark, jdbcType=VARCHAR}, #{item.numberCount, jdbcType=BIGINT}, #{loginUserId, jdbcType=BIGINT}, #{loginUserName, jdbcType=VARCHAR}, #{now}, #{loginUserId, jdbcType=BIGINT}, #{loginUserName, jdbcType=VARCHAR}, #{now}, #{item.subProcessCode, jdbcType=VARCHAR}, #{item.subProcessName, jdbcType=VARCHAR}, #{item.deptParentId, jdbcType=BIGINT}, #{item.deptParentName, jdbcType=VARCHAR} FROM DUAL
)

mapper.delete:
    	DELETE
		FROM
			T_PRD_DISPATCH_SECONDARY
		WHERE
			"ID" IN (
				SELECT
					T1. ID
				FROM
					T_PRD_DISPATCH_SECONDARY T1,
					SYS_DEPT T2
				WHERE
		        	T1.DEPT_ID = T2.ID
		            AND T1.WORK_PLAN_ID = #{workPlanId}
		            AND T1.DISPATCH_TYPE = #{dispatchType}


			            AND (T2.DEPT_NO like #{deptNo_like,jdbcType=VARCHAR}

			            	${canDispatchDept}

				        )


			)

mapper.select:
SELECT SHIPVOYAGE_ITEM_ID "shipvoyageItemId", TO_CHAR(A.WORK_DATE,'yyyy-mm-dd') || A.CLASS_NAME "shijianBanci", A.PROCESS_NAME "processName", A.DEPT_NAME "deptName", A.TON_PLAN "tonPlan" FROM T_PRD_WORK_PLAN A LEFT JOIN T_PRD_WORK_TICKET B ON A.ID = B.WORK_PLAN_ID
B.TICKET_TYPE = '1'
AND A.SHIPVOYAGE_ITEM_ID IN (
#{id}
)

SELECT TO_CHAR (T1.WORK_DATE, 'yyyy-mm-dd') || ' ' || T1.CLASS_NAME "className", T2.PROCESS_DETAIL_NAME "processDetailName", T2.PERSONNEL_NAME "personnelName", LISTAGG (T5.EQUIPMENT_NO, ',') WITHIN GROUP (ORDER BY T5.EQUIPMENT_NO) "equipmentNo", T2.DEPT_NAME "deptItemName", T2.TON "ton", T5.EQUIPMENT_TYPE_NAME "equipmentTypeName", TDSI.ID "shipvoyageItemId" FROM T_PRD_WORK_TICKET T1 LEFT JOIN T_PRD_WORK_TICKET_DETAIL T2 ON T1. ID = T2.WORK_TICKET_ID LEFT JOIN T_PRD_WORK_PLAN T3 ON T3. ID = T1.WORK_PLAN_ID LEFT JOIN T_DIS_SHIPVOYAGE TDS ON T3.SHIPVOYAGE_ID = TDS. ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON T3.SHIPVOYAGE_ITEM_ID = TDSI. ID LEFT JOIN T_PRD_WORK_TICKET_EQUIPMENT T5 ON T5.WORK_TICKET_DETAIL_ID = T2. ID WHERE WORK_TICKET_STATUS IN ('10','20') AND TICKET_TYPE = '1'
AND TDSI.ID IN (
#{id}
)
GROUP BY TO_CHAR (T1.WORK_DATE, 'yyyy-mm-dd') || ' ' || T1.CLASS_NAME, T2.PROCESS_DETAIL_NAME, T2.PERSONNEL_NAME, T2.DEPT_NAME, T2.TON, TDSI.ID, T2.TON, T5.EQUIPMENT_TYPE_NAME, T2.CAR_COUNT
